functions.example_code:
-- 总行数
SELECT COUNT(*) AS total FROM users;

-- 非空城市数
SELECT COUNT(city) AS has_city FROM users;

-- 去重城市数
SELECT COUNT(DISTINCT city) AS unique_cities FROM users;

SELECT name, score,
  ROW_NUMBER() OVER (ORDER BY score DESC) AS rn
FROM students;

SELECT name, score,
  RANK() OVER (ORDER BY score DESC) AS rk
FROM students;

SELECT name, score,
  DENSE_RANK() OVER (ORDER BY score DESC) AS drk
FROM students;

SELECT sale_date, amount,
  LAG(amount, 1) OVER (ORDER BY sale_date) AS prev
FROM daily_sales;

SELECT sale_date, amount,
  LEAD(amount, 1) OVER (ORDER BY sale_date) AS next_amt
FROM daily_sales;

SELECT TRANSFORM(ARRAY(1, 2, 3), x -> x * 2) AS doubled;
-- [2, 4, 6]

SELECT TRANSFORM(ARRAY('a','b'), x -> UPPER(x));
-- [A, B]

SELECT FROM_JSON(profile_json, 'name STRING, age INT') AS profile
FROM users;

-- 后续可用 profile.name 访问字段

SELECT PERCENTILE_APPROX(score, 0.5) AS p50,
       PERCENTILE_APPROX(score, array(0.25, 0.5, 0.75)) AS p25_50_75
FROM students;
